// Shared helpers for the eval harness.
//
// The eval is split into two halves on purpose:
//   - fetch.mjs  needs NCBI + ANTHROPIC_API_KEY. It writes extracted cards to
//     eval/cache/. Run it once; it is the only part that costs money.
//   - score.mjs  is pure and offline. It reads the cache and computes the
//     numbers. Re-running it is free, so the reported figures can be
//     regenerated by anyone with the repo, without an API key.
//
// That split is deliberate: it means the headline number is reproducible from
// committed artefacts rather than taken on trust.

import { readFileSync, writeFileSync, mkdirSync, existsSync } from 'node:fs';
import { fileURLToPath } from 'node:url';
import { dirname, join } from 'node:path';

const here = dirname(fileURLToPath(import.meta.url));

export const EVAL_DIR = here;
export const CACHE_DIR = join(here, 'cache');
export const CASES_PATH = join(here, 'cases.json');

/** The design dimensions a driver can be ranked into. Mirrors DRIVER_RANK's keys. */
export const SCORED_DIMENSIONS = [
  'assay', 'model', 'intervention', 'dose', 'timing',
  'endpoint', 'species', 'sampleSize', 'statistic',
];

/**
 * Minimal .env loader, mirroring the one in src/server.mjs so the eval follows
 * the same convention as the rest of the repo (no dotenv dependency, no
 * --env-file flag to remember). Real environment variables always win.
 */
export function loadEnv() {
  const p = join(EVAL_DIR, '..', '.env');
  if (!existsSync(p)) return;
  for (const line of readFileSync(p, 'utf8').split('\n')) {
    const m = line.match(/^\s*([A-Z_][A-Z0-9_]*)\s*=\s*(.*)\s*$/i);
    if (m && !process.env[m[1]]) process.env[m[1]] = m[2].replace(/^["']|["']$/g, '');
  }
}

export function loadCases() {
  const raw = JSON.parse(readFileSync(CASES_PATH, 'utf8'));
  return raw;
}

/**
 * Source depth is part of the cache key, not an incidental property of the
 * entry, so the two arms can coexist and can never be silently mixed.
 *
 *   'abstract'     — PRIMARY. Abstracts only. Symmetric and stable.
 *   'as-retrieved' — SECONDARY. Whatever src/ncbi.mjs returns, which upgrades to
 *                    PMC full text when the paper is in the OA subset.
 *
 * The primary arm is abstract-only because PMC OA membership drifts over time:
 * an as-retrieved number is not reproducible, and would change for reasons that
 * have nothing to do with the ranker. See cases.json > provenance.
 */
export const DEPTHS = ['abstract', 'as-retrieved'];
export const DEFAULT_DEPTH = 'abstract';

export function parseDepth(args) {
  const i = args.indexOf('--depth');
  if (i === -1) return DEFAULT_DEPTH;
  const d = args[i + 1];
  if (!DEPTHS.includes(d)) {
    throw new Error(`--depth must be one of: ${DEPTHS.join(', ')} (got "${d}")`);
  }
  return d;
}

export function cachePath(caseId, pmid, depth = DEFAULT_DEPTH) {
  return join(CACHE_DIR, `${caseId}__${pmid}__${depth}.json`);
}

/**
 * A cache entry is only admissible if it came from a real extraction run.
 *
 * This guard exists because of a real near-miss: while smoke-testing the
 * reporter, the cache was seeded from the repo's fixtures, whose study cards are
 * hand-written EXAMPLE extractions rather than model output. Scoring those would
 * have measured the ranker against idealised, human-authored cards and reported
 * it as the tool's accuracy — a flattering number with nothing behind it.
 * The eval refuses that input rather than trusting the operator to remember.
 */
export function isRealExtraction(entry) {
  if (!entry || typeof entry !== 'object') return false;
  if (!entry.extractedAt || !entry.model) return false;
  if (Number.isNaN(Date.parse(entry.extractedAt))) return false;
  if (/FIXTURE|GOLDEN|SMOKE|SYNTHETIC|EXAMPLE/i.test(String(entry.model))) return false;
  return true;
}

export function readCache(caseId, pmid, depth = DEFAULT_DEPTH) {
  const p = cachePath(caseId, pmid, depth);
  if (!existsSync(p)) return null;
  const entry = JSON.parse(readFileSync(p, 'utf8'));
  if (!isRealExtraction(entry)) {
    throw new Error(
      `Cache entry ${caseId}__${pmid}__${depth}.json is not a real extraction ` +
      `(model="${entry?.model}", extractedAt="${entry?.extractedAt}"). ` +
      `Refusing to score it. Delete eval/cache and run \`npm run eval:fetch\`.`,
    );
  }
  if (entry.depthArm && entry.depthArm !== depth) {
    throw new Error(
      `Cache entry ${caseId}__${pmid}__${depth}.json was extracted under the ` +
      `"${entry.depthArm}" arm. Refusing to mix arms.`,
    );
  }
  return entry;
}

export function writeCache(caseId, pmid, depth, payload) {
  mkdirSync(CACHE_DIR, { recursive: true });
  writeFileSync(cachePath(caseId, pmid, depth), JSON.stringify(payload, null, 2));
}

/**
 * Wilson score interval for a binomial proportion.
 *
 * Used instead of a bare percentage because n here is ~15. A point estimate
 * from 15 cases without an interval would be exactly the kind of unearned
 * precision this project exists to avoid: 60% from n=15 is compatible with a
 * true rate anywhere from roughly 35% to 80%. The interval is computed from the
 * observed counts — it is not a confidence score anyone invented.
 *
 * @param {number} successes
 * @param {number} n
 * @param {number} z  1.96 for 95%
 * @returns {{low:number, high:number}} bounds as proportions
 */
export function wilson(successes, n, z = 1.96) {
  if (n === 0) return { low: 0, high: 0 };
  const p = successes / n;
  const denom = 1 + (z * z) / n;
  const centre = p + (z * z) / (2 * n);
  const spread = z * Math.sqrt((p * (1 - p)) / n + (z * z) / (4 * n * n));
  return {
    low: Math.max(0, (centre - spread) / denom),
    high: Math.min(1, (centre + spread) / denom),
  };
}

export const pct = (x) => `${(x * 100).toFixed(1)}%`;

/** Format a proportion with its Wilson interval, e.g. "60.0% (95% CI 35.7-80.2%)". */
export function withCI(successes, n) {
  if (n === 0) return 'n/a (no cases)';
  const ci = wilson(successes, n);
  return `${pct(successes / n)} (95% CI ${pct(ci.low)}-${pct(ci.high)}) [${successes}/${n}]`;
}

/** Pad/truncate for table output. */
export const cell = (s, w) => String(s).slice(0, w).padEnd(w);
